const crypto = require('crypto');
const https = require('https');
const jwt = require('jsonwebtoken');

function makeRequest(url, headers) {
  return new Promise((resolve, reject) => {
    const options = {
      headers: {
        'Accept': 'application/json',
        ...headers
      }
    };
    https.get(url, options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        resolve({
          status: res.statusCode,
          headers: res.headers,
          body: data
        });
      });
    }).on('error', reject);
  });
}

async function main() {
  const magicbellEmail = process.env.MAGICBELL_EMAIL;
  const zealtRunId = process.env.ZEALT_RUN_ID;
  const apiKey = process.env.MAGICBELL_API_KEY;
  const secretKey = process.env.MAGICBELL_SECRET_KEY;

  let targetEmail;
  if (magicbellEmail.includes('@')) {
    targetEmail = `${magicbellEmail.split('@')[0]}+${zealtRunId}@gmail.com`;
  } else {
    targetEmail = `${magicbellEmail}+${zealtRunId}@gmail.com`;
  }

  console.log('Target Email:', targetEmail);

  // 1. Generate HMAC
  const hmac = crypto.createHmac('sha256', secretKey).update(targetEmail).digest('base64');
  console.log('Generated HMAC:', hmac);

  // 2. Fetch using HMAC headers
  const hmacHeaders = {
    'X-MAGICBELL-API-KEY': apiKey,
    'X-MAGICBELL-USER-EMAIL': targetEmail,
    'X-MAGICBELL-USER-HMAC': hmac
  };
  const hmacRes = await makeRequest('https://api.magicbell.com/notifications', hmacHeaders);
  console.log('HMAC Request Status:', hmacRes.status);
  console.log('HMAC Request Body:', hmacRes.body);

  // 3. Generate JWT
  const payload = {
    user_email: targetEmail,
    api_key: apiKey
  };
  const userJwt = jwt.sign(payload, secretKey, {
    algorithm: 'HS256',
    expiresIn: '1y'
  });
  console.log('Generated JWT:', userJwt);

  // 4. Fetch using JWT header
  const jwtHeaders = {
    'Authorization': `Bearer ${userJwt}`
  };
  const jwtRes = await makeRequest('https://api.magicbell.com/notifications', jwtHeaders);
  console.log('JWT Request Status:', jwtRes.status);
  console.log('JWT Request Body:', jwtRes.body);
}

main().catch(console.error);

